#' Continuous Meta-Analysis
#'
#' 
#' @param data .
#' @param studyLabel .
#' @param meanE .
#' @param sdE .
#' @param nE .
#' @param meanC .
#' @param sdC .
#' @param nC .
#' @param sm .
#' @param methodSmd .
#' @param model .
#' @param methodTau .
#' @param methodRandomCi .
#' @param prediction .
#' @param confidenceLevel .
#' @param showSummary .
#' @param forestPlot .
#' @param forestLayout .
#' @param sortBy .
#' @param labelLeft .
#' @param labelRight .
#' @param labelE .
#' @param labelC .
#' @param forestMode .
#' @param forestWidthAdjust .
#' @param forestWidthUnit .
#' @param forestHeightAdjust .
#' @param forestHeightUnit .
#' @param xlimMode .
#' @param xlimLower .
#' @param xlimUpper .
#' @param addrowsMode .
#' @param addrowsBelowOverall .
#' @param colgap .
#' @param colgapUnit .
#' @param colgapForest .
#' @param colgapForestUnit .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$text} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$plot} \tab \tab \tab \tab \tab an image \cr
#' }
#'
#' @export
metaCont <- function(
    data,
    studyLabel,
    meanE,
    sdE,
    nE,
    meanC,
    sdC,
    nC,
    sm = "md",
    methodSmd = "Hedges",
    model = "both",
    methodTau = "REML",
    methodRandomCi = "classic",
    prediction = FALSE,
    confidenceLevel = 95,
    showSummary = TRUE,
    forestPlot = TRUE,
    forestLayout = "meta",
    sortBy = "none",
    labelLeft = "",
    labelRight = "",
    labelE = "Experimental",
    labelC = "Control",
    forestMode = "basic",
    forestWidthAdjust = 0,
    forestWidthUnit = "mm",
    forestHeightAdjust = 0,
    forestHeightUnit = "mm",
    xlimMode = "auto",
    xlimLower = -20,
    xlimUpper = 20,
    addrowsMode = "auto",
    addrowsBelowOverall = 0,
    colgap = 2,
    colgapUnit = "mm",
    colgapForest = 2,
    colgapForestUnit = "mm") {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("metaCont requires jmvcore to be installed (restart may be required)")

    if ( ! missing(studyLabel)) studyLabel <- jmvcore::resolveQuo(jmvcore::enquo(studyLabel))
    if ( ! missing(meanE)) meanE <- jmvcore::resolveQuo(jmvcore::enquo(meanE))
    if ( ! missing(sdE)) sdE <- jmvcore::resolveQuo(jmvcore::enquo(sdE))
    if ( ! missing(nE)) nE <- jmvcore::resolveQuo(jmvcore::enquo(nE))
    if ( ! missing(meanC)) meanC <- jmvcore::resolveQuo(jmvcore::enquo(meanC))
    if ( ! missing(sdC)) sdC <- jmvcore::resolveQuo(jmvcore::enquo(sdC))
    if ( ! missing(nC)) nC <- jmvcore::resolveQuo(jmvcore::enquo(nC))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(studyLabel), studyLabel, NULL),
            `if`( ! missing(meanE), meanE, NULL),
            `if`( ! missing(sdE), sdE, NULL),
            `if`( ! missing(nE), nE, NULL),
            `if`( ! missing(meanC), meanC, NULL),
            `if`( ! missing(sdC), sdC, NULL),
            `if`( ! missing(nC), nC, NULL))


    options <- metaContOptions$new(
        studyLabel = studyLabel,
        meanE = meanE,
        sdE = sdE,
        nE = nE,
        meanC = meanC,
        sdC = sdC,
        nC = nC,
        sm = sm,
        methodSmd = methodSmd,
        model = model,
        methodTau = methodTau,
        methodRandomCi = methodRandomCi,
        prediction = prediction,
        confidenceLevel = confidenceLevel,
        showSummary = showSummary,
        forestPlot = forestPlot,
        forestLayout = forestLayout,
        sortBy = sortBy,
        labelLeft = labelLeft,
        labelRight = labelRight,
        labelE = labelE,
        labelC = labelC,
        forestMode = forestMode,
        forestWidthAdjust = forestWidthAdjust,
        forestWidthUnit = forestWidthUnit,
        forestHeightAdjust = forestHeightAdjust,
        forestHeightUnit = forestHeightUnit,
        xlimMode = xlimMode,
        xlimLower = xlimLower,
        xlimUpper = xlimUpper,
        addrowsMode = addrowsMode,
        addrowsBelowOverall = addrowsBelowOverall,
        colgap = colgap,
        colgapUnit = colgapUnit,
        colgapForest = colgapForest,
        colgapForestUnit = colgapForestUnit)

    analysis <- metaContClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

